void buildAP(){
for(int i=0;i<n;i++){
for(int j=0;j<m;j++){
if(g[i][j] != '.') continue;
AP ap;
for(int k=0;k<9;k++){
int x=i+dx[k], y=j+dy[k];
if(!in(x,y)) continue;
ap.cells.push_back({x,y});
if(g[x][y]=='.'){
ap.dots.push_back(id[x][y]);
}
}
apList.push_back(ap);
}
}
}
